RETURNS_RB_2_PAYLOAD=$(echo "{\"name\":\"Cross-Border Return Processing\",\"description\":\"Customs considerations, duty refund procedures, and logistics coordination for international customer returns, including documentation requirements and restricted product categories.\",\"trigger\":\"manual\",\"triggerConditions\":[{\"trigger\":\"return_request_international\",\"customerCountry\":\"non_domestic\"}],\"steps\":[{\"order\":1,\"action\":\"Validate product category is not export-controlled, CITES-restricted, or subject to destination country import restrictions before accepting return\"},{\"order\":2,\"action\":\"Generate RMA with DHL Express or equivalent international carrier — include commercial invoice, return reason code, and customs declaration (HS code, value)\"},{\"order\":3,\"action\":\"Advise customer: original customs duties and import taxes are not refundable by seller — only product price and domestic taxes\"},{\"order\":4,\"action\":\"For EU returns under Distance Selling Regulations: customer has 14-day cooling-off right; seller must refund including original shipping within 14 days of return receipt\"},{\"order\":5,\"action\":\"On receipt at customs clearance: verify customs documentation matches physical shipment before accepting into facility\"},{\"order\":6,\"action\":\"Process refund in customer's original currency at the exchange rate used on the original invoice — do not expose company to FX risk on return\"},{\"order\":7,\"action\":\"For hazardous or regulated products: verify country-specific disposal requirements; do not return to stock if import regulations prohibit resale\"}],\"expectedOutcome\":\"\",\"rollbackProcedure\":null,\"escalationMatrix\":{},\"tags\":[],\"status\":\"active\",\"version\":\"1.0\",\"industry\":\"enterprise\",\"domain\":\"Order-to-Cash\"}" | jq -c \
