RETURNS_RB_3_PAYLOAD=$(echo "{\"name\":\"Damaged in Transit Carrier Claim\",\"description\":\"Carrier damage claim filing procedure and customer resolution process for items damaged during return shipment, covering evidence collection, claim submission, and customer resolution independent of claim status.\",\"trigger\":\"manual\",\"triggerConditions\":[{\"event\":\"inspection_defect_type\",\"defectCode\":\"DMG-TRANSIT\"}],\"steps\":[{\"order\":1,\"action\":\"Collect and preserve all evidence: inspection photos (minimum 8 photos showing all damage angles), packaging photos, weight at receipt, inspection report\"},{\"order\":2,\"action\":\"File carrier damage claim within carrier's required window (UPS: 9 months; FedEx: 60 days; USPS: 60 days) — do not delay\"},{\"order\":3,\"action\":\"Issue customer resolution immediately — do not wait for carrier claim outcome: full refund if item unreturnable; replacement ship if preferred\"},{\"order\":4,\"action\":\"Retain damaged item at receiving facility in original packaging for carrier inspection — carrier has right to inspect for up to 30 days\"},{\"order\":5,\"action\":\"For claims > $1,000: notify Logistics Manager; monitor claim status weekly; follow up with carrier at Day 7, Day 14, Day 30\"},{\"order\":6,\"action\":\"On claim settlement: post recovery to Freight Claims clearing account; reconcile against cost of resolution issued to customer\"},{\"order\":7,\"action\":\"If carrier denies claim: review denial reason; appeal if denial is procedural; escalate to carrier account manager if appeal needed\"}],\"expectedOutcome\":\"\",\"rollbackProcedure\":null,\"escalationMatrix\":{},\"tags\":[],\"status\":\"active\",\"version\":\"1.0\",\"industry\":\"enterprise\",\"domain\":\"Order-to-Cash\"}" | jq -c \
