RETURNS_RB_4_PAYLOAD=$(echo "{\"name\":\"Refund Processing Failure Recovery\",\"description\":\"Manual refund procedure, customer notification, and retry logic when automated refund processing fails due to payment processor error, closed account, expired card, or system outage.\",\"trigger\":\"manual\",\"triggerConditions\":[{\"event\":\"refund_processing_failed\",\"retryCount\":2}],\"steps\":[{\"order\":1,\"action\":\"Identify failure reason: payment processor decline, closed/expired card, account number change, system timeout, or currency mismatch\"},{\"order\":2,\"action\":\"For closed/expired card: contact customer immediately to obtain alternative refund method; offer store credit if unable to reach within 24 hours\"},{\"order\":3,\"action\":\"For payment processor error: wait 4 hours and retry once; if second failure, escalate to Treasury for manual wire or check issuance\"},{\"order\":4,\"action\":\"For system outage: log all pending refunds in manual queue; process in batch once system restored; ensure Regulation Z deadline not breached\"},{\"order\":5,\"action\":\"Notify customer of delay with honest explanation and revised refund date; per Regulation Z, refund must complete within 7 business days of return receipt\"},{\"order\":6,\"action\":\"If Regulation Z 7-day deadline at risk: escalate to Finance Controller; authorise manual check issuance to meet regulatory obligation\"},{\"order\":7,\"action\":\"Document all failed attempts, retry history, and final resolution method in the RMA audit trail\"}],\"expectedOutcome\":\"\",\"rollbackProcedure\":null,\"escalationMatrix\":{},\"tags\":[],\"status\":\"active\",\"version\":\"1.0\",\"industry\":\"enterprise\",\"domain\":\"Order-to-Cash\"}" | jq -c \
