RETURNS_RB_6_PAYLOAD=$(echo "{\"name\":\"High-Volume Return Event Response\",\"description\":\"Surge capacity and expedited processing procedure for high-volume return events such as product recalls, seasonal post-holiday spikes, or major product defect discoveries.\",\"trigger\":\"manual\",\"triggerConditions\":[{\"metric\":\"daily_return_volume\",\"window\":\"1d\",\"operator\":\"gt\",\"threshold\":500}],\"steps\":[{\"order\":1,\"action\":\"Classify surge type: product recall (safety), defect batch, seasonal spike, or promotional return wave — response priority differs by type\"},{\"order\":2,\"action\":\"For product recall: immediately notify Quality, Legal, and Product Safety; activate CPSC reporting process; do NOT wait for standard inspection — accept all returns unconditionally\"},{\"order\":3,\"action\":\"Increase auto-approval RMA threshold temporarily from $500 to $2,000 for standard return types to reduce specialist queue\"},{\"order\":4,\"action\":\"Activate overflow receiving at secondary DC; redirect 50% of return volume if primary CRC queue exceeds 48-hour SLA\"},{\"order\":5,\"action\":\"Notify carrier partners of surge: request additional pickup windows; pre-purchase label blocks\"},{\"order\":6,\"action\":\"Prioritise Regulation Z compliance: ensure no card refund exceeds 7-day processing window regardless of volume\"},{\"order\":7,\"action\":\"Stand up customer communication surge response: proactive portal banner with realistic timelines; pre-build status update templates\"},{\"order\":8,\"action\":\"Daily surge management stand-up until volume returns to baseline; document incident for post-mortem\"}],\"expectedOutcome\":\"\",\"rollbackProcedure\":null,\"escalationMatrix\":{},\"tags\":[],\"status\":\"active\",\"version\":\"1.0\",\"industry\":\"enterprise\",\"domain\":\"Order-to-Cash\"}" | jq -c \
