CONTRACT_RB_5_PAYLOAD=$(echo "{\"name\":\"Contract Data Load Failure Recovery\",\"description\":\"Validation checks, manual entry fallback, and reconciliation process when contract ingestion fails, ensuring no transactions proceed without correct pricing governance.\",\"trigger\":\"manual\",\"triggerConditions\":[{\"event\":\"contract_parse_failure\",\"parseConfidence\":\"lt_0.70\"}],\"steps\":[{\"order\":1,\"action\":\"Identify failure reason: document format not supported, required fields missing, logical inconsistency in pricing structure, or system error\"},{\"order\":2,\"action\":\"Notify Contract Management team immediately: provide specific error details, affected contract ID, and customer impacted\"},{\"order\":3,\"action\":\"Flag customer account in pricing system: apply 'PENDING CONTRACT' hold — route all new orders for manual pricing verification until contract loaded\"},{\"order\":4,\"action\":\"Contract Management to review source document and correct issues: fix document structure, fill missing fields, or resolve pricing inconsistencies\"},{\"order\":5,\"action\":\"Resubmit corrected contract for automated parsing; if second failure, initiate manual key entry by Contract Analyst with supervisor review\"},{\"order\":6,\"action\":\"Post-load validation: verify 100% of extracted pricing tiers against contract PDF by spot-check (minimum 3 tiers)\"},{\"order\":7,\"action\":\"Release PENDING CONTRACT hold; notify account manager that contract is active and compliant\"},{\"order\":8,\"action\":\"Retroactive compliance check: review any transactions processed during the hold period against the now-loaded contract terms\"}],\"expectedOutcome\":\"\",\"rollbackProcedure\":null,\"escalationMatrix\":{},\"tags\":[],\"status\":\"active\",\"version\":\"1.0\",\"industry\":\"enterprise\",\"domain\":\"Order-to-Cash\"}" | jq -c \
